#include <stdio.h>
int main() {
    int N;
    scanf("%d", &N);
    int totalRuns = 0, totalWickets = 0;
    int prevRuns = 0;
    for (int i = 0; i < N; i++) {
        int runs, wickets;
        scanf("%d %d", &runs, &wickets);
        if (wickets > 10 || runs < prevRuns) {
            printf("NO\n");
            return 0;
        }
        totalRuns += runs - prevRuns;
        totalWickets = wickets;
        prevRuns = runs;
    }
    printf("YES\n");
    return 0;
}

